import multiprocessing
import time
import math
from multiprocessing import Pool, Process, Queue, Value, Array, Manager

# CPU-bound task
def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            return False
    return True

def find_primes_in_range(start, end):
    primes = []
    for num in range(start, end):
        if is_prime(num):
            primes.append(num)
    return primes

# Basic process
if __name__ == '__main__':
    p = Process(target=find_primes_in_range, args=(0, 100000))
    p.start()
    p.join()
    print("Process completed")

# Process pool for parallel computation
if __name__ == '__main__':
    chunk_size = 25000
    ranges = [(i, i + chunk_size) for i in range(0, 100000, chunk_size)]

    start = time.time()
    with Pool(processes=4) as pool:
        results = pool.starmap(find_primes_in_range, ranges)

    all_primes = []
    for result in results:
        all_primes.extend(result)

    print(f"Found {len(all_primes)} primes in {time.time() - start:.2f}s")

# Shared memory with Value and Array
def increment(counter, lock, arr):
    for _ in range(1000):
        with lock:
            counter.value += 1
            arr[0] = counter.value

if __name__ == '__main__':
    counter = Value('i', 0)
    lock = multiprocessing.Lock()
    arr = Array('i', [0])

    processes = [Process(target=increment, args=(counter, lock, arr)) for _ in range(10)]

    for p in processes:
        p.start()
    for p in processes:
        p.join()

    print(f"Counter: {counter.value}")

# Queue for inter-process communication
class Worker(Process):
    def __init__(self, task_queue, result_queue):
        super().__init__()
        self.task_queue = task_queue
        self.result_queue = result_queue

    def run(self):
        while True:
            task = self.task_queue.get()
            if task is None:
                break
            result = task * task
            self.result_queue.put(result)

if __name__ == '__main__':
    task_q = Queue()
    result_q = Queue()

    workers = [Worker(task_q, result_q) for _ in range(4)]
    for w in workers:
        w.start()

    # Add tasks
    for i in range(20):
        task_q.put(i)

    # Stop workers
    for _ in workers:
        task_q.put(None)

    # Collect results
    results = []
    for _ in range(20):
        results.append(result_q.get())

    for w in workers:
        w.join()

    print(f"Results: {results}")

# Manager for shared state
if __name__ == '__main__':
    manager = Manager()
    shared_dict = manager.dict()
    shared_list = manager.list()

    def update_data(pid, data):
        shared_dict[pid] = data
        shared_list.append(pid)

    processes = []
    for i in range(5):
        p = Process(target=update_data, args=(i, f"Data_{i}"))
        p.start()
        processes.append(p)

    for p in processes:
        p.join()

    print(f"Shared dict: {dict(shared_dict)}")
    print(f"Shared list: {list(shared_list)}")
